#include<bits/stdc++.h>
using namespace std;

class queue {
	public:
		static const int maxn = 1000001;
		int n, k, a[maxn];
		int q[maxn], head, tail, p[maxn];

		void in() {
			scanf("%d %d", &n, &k);
			for (int i = 1; i <= n; ++i)
				scanf("%d", &a[i]);
		}

		void max()

		{
			head = 1;
			tail = 0;
			for (int i = 1; i <= n; ++i) {
				while (head <= tail && q[tail] <= a[i])
					tail--;
				q[++tail] = a[i];
				p[tail] = i;
				while (p[head] <= i - k)
					head++;
				if (i >= k)printf("%d ", q[head]);
			}
			printf("\n");
		}

		void min() {
			head = 1;
			tail = 0;
			for (int i = 1; i <= n; ++i) {
				while (head <= tail && q[tail] >= a[i])
					tail--;
				q[++tail] = a[i];
				p[tail] = i;
				while (p[head] <= i - k)
					head++;
				if (i >= k)printf("%d ", q[head]);
			}
			printf("\n");

		}
} w;

int main() {
	w.in();
	w.min();
	w.max();
	return 0;
}
